                    e.printStackTrace();
                    &lt;span class=&#34;hljs-keyword&#34;&gt;break&lt;/span&gt;;
                }
            }
        }, &lt;span class=&#34;hljs-string&#34;&gt;&#34;clean&#34;&lt;/span&gt;).start();
